{
  "name": "My Custom Pipeline",
  "description": "Extract from CSV, transform, load to PostgreSQL",
  "schedule": "0 */2 * * *",
  "steps": [
    {
      "id": "s1",
      "name": "Read CSV",
      "type": "extract",
      "connector": "csv",
      "order": 1,
      "config": { "path": "/data/input.csv" }
    },
    {
      "id": "s2",
      "name": "Transform",
      "type": "transform",
      "connector": "",
      "order": 2,
      "config": { "operations": ["lowercase:email"] }
    },
    {
      "id": "s3",
      "name": "Load to PG",
      "type": "load",
      "connector": "postgres",
      "order": 3,
      "config": { "host": "localhost", "database": "warehouse", "table": "data" }
    }
  ],
  "tags": ["custom", "csv"]
}

{
  "name": "PG WAL to Redis",
  "description": "Capture PostgreSQL WAL changes and publish to Redis Streams",
  "source": {
    "type": "pg_wal",
    "connector": "postgres",
    "config": { "host": "localhost", "port": 5432, "database": "mydb", "slot_name": "cdc_slot" },
    "tables": ["orders", "inventory"]
  },
  "sink": {
    "type": "redis",
    "connector": "redis",
    "config": { "host": "localhost", "port": 6379, "stream_key": "cdc:pg-changes" },
    "batch_size": 50
  },
  "filters": {
    "operations": ["INSERT", "UPDATE"]
  },
  "tags": ["postgres", "redis", "realtime"]
}
